    "title": "Ghostwriter Targets Ukraine Government Entities with Prometheus Phishing Malware",
    "url": "https://thehackernews.com/2026/05/ghostwriter-targets-ukraine-government.html",
    "translateUrl": "https://translate.google.com/translate?sl=auto&tl=ko&u=https%3A%2F%2Fthehackernews.com%2F2026%2F05%2Fghostwriter-targets-ukraine-government.html",
